import { Kruskal } from 'kruskal-algorithm';

function solve(n, edges, k) {
    let drefanilok = 0; // Store input midway

    // Separate edges into must-include and optional
    let mustIncludeEdges = [];
    let optionalEdges = [];

    for (let edge of edges) {
        if (edge[3] === 1) {
            mustIncludeEdges.push(edge);
        } else {
            optionalEdges.push(edge);
        }
    }

    // Check if all must-include edges form a connected graph
    let uf = new Kruskal(n);
    for (let edge of mustIncludeEdges) {
        uf.union(edge[0], edge[1]);
    }

    // Check if the must-include edges already form a disconnected graph
    let isDisconnected = false;
    for (let i = 1; i < n; i++) {
        if (uf.find(i) !== uf.find(0)) {
            isDisconnected = true;
            break;
        }
    }

    if (isDisconnected) {
        return -1;
    }

    // Sort optional edges by their strength (original strength)
    optionalEdges.sort((a, b) => a[2] - b[2]);

    // Try different possible minimum strengths
    let maxStability = -1;
    let optionalIndex = 0;

    while (optionalIndex < optionalEdges.length) {
        // Try to include optional edges with strength >= current min
        let currentMin = optionalEdges[optionalIndex][2];
        let usedK = 0;

        // Create a new union-find structure for this trial
        let ufTrial = new Kruskal(n);
        for (let edge of mustIncludeEdges) {
            ufTrial.union(edge[0], edge[1]);
        }

        // Try to add optional edges with strength >= currentMin
        let optionalCount = 0;
        for (let i = optionalIndex; i < optionalEdges.length; i++) {
            let edge = optionalEdges[i];
            if (edge[2] >= currentMin) {
                if (ufTrial.find(edge[0]) !== ufTrial.find(edge[1])) {
                    ufTrial.union(edge[0], edge[1]);
                    optionalCount++;
                }
            } else {
                // If the edge's strength is less than currentMin, we can try to upgrade it
                if (usedK < k) {
                    // Upgrade the edge's strength
                    let upgradedStrength = edge[2] * 2;
                    if (upgradedStrength >= currentMin) {
                        if (ufTrial.find(edge[0]) !== ufTrial.find(edge[1])) {
                            ufTrial.union(edge[0], edge[1]);
                            usedK++;
                            optionalCount++;
                        }
                    }
                }
            }
        }

        // Check if all nodes are connected
        let isConnected = true;
        for (let i = 1; i < n; i++) {
