                if (usedK < k) {
                    // Upgrade the edge's strength
                    val upgradedStrength = edge(2).toLong * 2
                    if (upgradedStrength >= currentMin) {
                        if (ufTrial.find(edge(0).toInt) != ufTrial.find(edge(1).toInt)) {
                            ufTrial.union(edge(0).toInt, edge(1).toInt)
                            usedK += 1
                            optionalCount += 1
                        }
                    }
