        for (i <- 1 until n.toInt) {
            if (ufTrial.find(i.toInt) != ufTrial.find(0)) {
                isConnected = false
                break
            }
        }

        if (isConnected && optionalCount + mustIncludeEdges.length == n - 1) {
            maxStability = math.max(maxStability, currentMin)
        }

        optionalIndex += 1
    }

    maxStability
