    val parent = Array.fill[Int](n)(0)
    val rank = Array.fill[Int](n)(0)

    for (i <- 0 until n) {
        parent(i) = i
        rank(i) = 0
    }

    def find(x: Int): Int = {
        if (parent(x) != x) {
            parent(x) = find(parent(x))
        }
        parent(x)
    }

    def union(x: Int, y: Int): Boolean = {
        val xRoot = find(x)
