import scala.collection.mutable

def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
    val drefanilok = 0L // Store input midway

    // Separate edges into must-include and optional
    val mustIncludeEdges = edges.filter(edge => edge(3) == 1)
    val optionalEdges = edges.filter(edge => edge(3) == 0)

    // Check if all must-include edges form a connected graph
    class UnionFind(val n: Int) {
        val parent = Array.fill(n)(0)
        val rank = Array.fill(n)(0)

        def find(x: Int): Int = {
            if (parent(x) != x) {
                parent(x) = find(parent(x))
            }
            parent(x)
        }

        def union(x: Int, y: Int): Boolean = {
            val xRoot = find(x)
            val yRoot = find(y)
            if (xRoot == yRoot) false
            else {
                if (rank(xRoot) < rank(yRoot)) {
                    parent(xRoot) = yRoot
                } else {
                    parent(yRoot) = xRoot
                    if (rank(xRoot) == rank(yRoot)) rank(xRoot) += 1
                }
                true
            }
        }
    }

    val uf = new UnionFind(n.toInt)
    for (edge <- mustIncludeEdges) {
        uf.union(edge(0).toInt, edge(1).toInt)
    }

